using Microsoft.Extensions.ML;
using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model at startup so the .zip is available for the pool
using var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
var trainingService = new ModelTrainingService(loggerFactory.CreateLogger<ModelTrainingService>());
trainingService.TrainAndSave();

var modelPath = trainingService.GetModelPath();

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

// Extract label names from the trained model's Score column
var mlContext = new MLContext();
var model = mlContext.Model.Load(modelPath, out var schema);
var outputSchema = model.GetOutputSchema(schema);
var scoreColumn = outputSchema["Score"];
var slotNames = new VBuffer<ReadOnlyMemory<char>>();
scoreColumn.GetSlotNames(ref slotNames);
var labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
builder.Services.AddSingleton(new LabelMap(labels));

var app = builder.Build();
app.MapControllers();
app.Run();

